loop {
    // Run shared per-tick housekeeping (async messages, timers, auto-save, etc.)
    {
        let _span = tracing::info_span!("editor_tick").entered();
        if fresh::app::editor_tick(editor, || {
            terminal.clear()?;
            Ok(())
        })? {
            needs_render = true;
        }
