use fresh::app::Editor;
use fresh::input::commands::get_all_commands;
use fresh::input::keybindings::Action;

#[test]
fn repaint_display_command_is_registered_for_command_palette() {
    let command = get_all_commands()
        .into_iter()
        .find(|command| command.action == Action::RepaintDisplay)
        .expect("Repaint Display command should be available from the command palette");

    assert!(command.contexts.is_empty(), "command should work in every context");
    assert!(
        command.name.to_lowercase().contains("repaint")
            || command.name.to_lowercase().contains("redraw")
            || command.name.to_lowercase().contains("refresh"),
        "command should be discoverable by repaint/redraw/refresh wording: {}",
        command.name
    );
}

#[test]
fn repaint_display_action_requests_full_redraw() {
    let mut editor = Editor::new(80, 24).expect("editor should initialize");
    assert!(!editor.take_full_redraw_request());

    editor.handle_action(Action::RepaintDisplay).unwrap();

    assert!(
        editor.take_full_redraw_request(),
        "repaint action should request a terminal clear and full render"
    );
    assert!(
        !editor.take_full_redraw_request(),
        "full redraw request should be consumed after one tick"
    );
}

