                                    | (Some(b'['), Some(b']'))
                                    | (Some(b'{'), Some(b'}'))
                                    | (Some(b'"'), Some(b'"'))
                                    | (Some(b'\''), Some(b'\''))
                                    | (Some(b'`'), Some(b'`'))
                            );

