    fn test_move_line_down_large_file_selection_block() {
        use crate::model::buffer::TextBuffer;
        use std::fs;
        use tempfile::tempdir;

        let temp_dir = tempdir().unwrap();
        let test_file = temp_dir.path().join("move_line_down_large_file.txt");

