        state.apply(
            &mut cursors,
            &Event::Insert {
                position: 0,
                text: "12345\n123\n12345".to_string(),
                cursor_id: CursorId(0),
            },
        );

        // Move cursor to position 3 (column 3 of first line)
        state.apply(
            &mut cursors,
            &Event::MoveCursor {
                cursor_id: CursorId(0),
                old_position: 15,
                new_position: 3,
                old_anchor: None,
                new_anchor: None,
                old_sticky_column: 0,
                new_sticky_column: 0,
            },
        );

