        println!("After backspace: cursor at {}", cursors.primary().position);
        assert_eq!(
            state.buffer.to_string().unwrap(),
            "HelloNew LineWorld!",
            "Lines should be joined"
        );
        assert_eq!(
            cursors.primary().position,
            13,
